// components/Banner.tsx
import React from "react";
import "../users/styles/components_styles.css"; // adjust if needed

export interface MovieBannerProps {
  image: string;
  children: React.ReactNode;
}

const Banner: React.FC<MovieBannerProps> = ({ image, children }) => {
  return (
    <div
      className="banner"
      style={{
        backgroundImage: `url(${image})`,
        backgroundSize: "cover",
        backgroundPosition: "center",
        height: "60vh",
        display: "flex",
        flexDirection: "column",
        justifyContent: "flex-end",
        position: "relative",
      }}
    >
      <div className="details-overlay">{children}</div>
    </div>
  );
};

export default Banner;
